#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const LD eps = 1e-10;
const LD D = 0.999;
struct buildings{LD x,y,r;}a[105];
struct boss_{LD x,y;}b[1005];
LL n,m,now,Ans;LD R,sx,sy;
map<pLL,bool> vis;
LD Dist(LD x_1,LD y_1,LD x_2,LD y_2){
    return sqrt((x_1-x_2)*(x_1-x_2)+(y_1-y_2)*(y_1-y_2));
}
LL calc(LD X,LD Y){
    LD res=R;LL sum=0;
    for(int i=1;i<=n;i++)
        res=min(res,Dist(X,Y,a[i].x,a[i].y)-a[i].r);
    if(res<0)return 0;
    for(int i=1;i<=m;i++)
        if(Dist(X,Y,b[i].x,b[i].y)<=res)sum++;
    return sum;
}
LD Rand01(){
    return (1.0*rand()/RAND_MAX);
}
void SA(){
    LD T=2000.0;Ans=max(Ans,now);
    while(T>eps){
        LD tx=sx+2*T*Rand01()-T;
        LD ty=sy+2*T*Rand01()-T;
        LL tmp=calc(tx,ty);LD Delta=now-tmp;
        if(Delta<0)now=tmp,sx=tx,sy=ty,Ans=max(Ans,tmp);
        else if(exp(Delta/T)<Rand01())now=tmp,sx=tx,sy=ty;
        T*=D;
    }return;
}
int main(){
    srand(132052);
    cin>>n>>m>>R;
    for(int i=1;i<=n;i++)
        cin>>a[i].x>>a[i].y>>a[i].r;
    for(int i=1;i<=m;i++){
        cin>>b[i].x>>b[i].y;
        sx+=b[i].x,sy+=b[i].y;
    }sx/=m,sy/=m;now=calc(sx,sy);SA();
    for(int i=1;i<=m;i++){
        sx=b[i].x,sy=b[i].y;
        if(((LD)clock()/CLOCKS_PER_SEC)>0.8)break;
        if(!vis[{sx,sy}]&&rand()%4!=0)
            now=calc(sx,sy),SA(),vis[{sx,sy}]=1;
    }cout<<Ans<<"\n";
    return 0;
}
